# E2-Skeptic three-route assess for S44-T1-A-E2
def assess(record: dict) -> str:
    required = {"case_id", "lint", "types", "tests", "matrix", "supported"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    ok = (
        record.get("lint") is True
        and record.get("types") is True
        and record.get("tests") is True
        and set(record.get("matrix") or []) == set(record.get("supported") or [])
    )
    return "PASS" if ok else "FAIL_CI_GATE"

valid = {"case_id": "CASO-PIU-044-1A", **{"lint":True,"types":True,"tests":True,"matrix":{"3.11","3.12"},"supported":{"3.11","3.12"}}}
invalid = {**valid, "tests": False}
incomplete = {k: v for k, v in valid.items() if k != "matrix"}
print(assess(valid), assess(invalid), assess(incomplete))

# E2-Skeptic packet-local for S44-T1-A-E3
def decide(record: dict) -> str:
    required = {"case_id", "lint", "types", "tests", "matrix", "supported"}
    missing = sorted(required - record.keys())
    if missing:
        return "CONTINUE"
    return "CONTINUE" if record["lint"] or record["types"] or record["tests"] else "FAIL_CI_GATE"

valid = {"case_id": "CASO-PIU-044-1A", **{"lint":True,"types":True,"tests":True,"matrix":{"3.11","3.12"},"supported":{"3.11","3.12"}}}
invalid = {"case_id": "CASO-PIU-044-1A", **{"lint":True,"types":False,"tests":True,"matrix":{"3.10","3.12"},"supported":{"3.11","3.12"}}}
uncertain = {**valid}
uncertain.pop("supported")
results = [decide(item) for item in (valid, invalid, uncertain)]
print(*results)

# E2-Skeptic three-route assess for S44-T1-B-E2
def assess(record: dict) -> str:
    required = {'artifact_digest', 'retention_days', 'cache_key', 'cache_miss_passes', 'conditions_cover_tags', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    try:
        ok = not (not record["cache_miss_passes"] or not record["conditions_cover_tags"])
    except Exception:
        return 'DISCARD_PIPELINE_RESULT'
    return 'PASS' if ok else 'DISCARD_PIPELINE_RESULT'

record = {"case_id": "CASO-PIU-044-1B", **{"cache_key":"lock-abc","cache_miss_passes":True,"artifact_digest":"sha256:def","retention_days":14,"conditions_cover_tags":True}}
valid = dict(record)
invalid = dict(valid)
# adverse: invert first boolean flag if any
_flipped=False
for _k,_v in list(invalid.items()):
    if isinstance(_v,bool):
        invalid[_k]= (not _v)
        _flipped=True
        break
if not _flipped and isinstance(invalid.get('stages'), list):
    invalid['stages']=list(reversed(invalid['stages']))
elif not _flipped and 'dependencies' in invalid:
    invalid['dependencies']=[["domain","infrastructure"]]
incomplete={k:v for k,v in valid.items() if k != 'conditions_cover_tags'}
print(assess(valid), assess(invalid), assess(incomplete))

